{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires an optimization strategy for spatial search under uncertainty and cost constraints. I am decomposing this into a search strategy component and a probabilistic estimation component.",
  "helpers": [
    {
      "label": "search_strategy_optimizer",
      "instructions": "Develop an algorithmic strategy to minimize drilling and query costs. This should involve a decision tree or a greedy heuristic that selects the next probe location based on the known polyomino shapes, the results of previous noisy aggregate queries, and the potential information gain regarding the location of the oil fields."
    },
    {
      "label": "probabilistic_field_estimator",
      "instructions": "Create a mathematical model to estimate the probability distribution of oil-containing cells across the grid. This model must take noisy aggregate query results and previous drilling data as inputs to update the likelihood of each cell being part of a specific polyomino shape, accounting for the geometric constraints of the known shapes."
    }
  ],
  "synthesis_brief": "The parent agent will use the probabilistic field estimator to maintain a belief map of the oil locations. The search strategy optimizer will then use this belief map to select the most cost-effective next action (drilling or querying) until the uncertainty is low enough to make a final guess with minimal cost."
}
```

